### Async Test Helpers
```rust
/// Run async test code with a fresh lab runtime.
///
/// # Example
/// ```
/// #[test]
/// fn my_async_test() {
///     run_test(async {
///         // async test code
///     });
/// }
/// ```
pub fn run_test<F, Fut>(f: F)
where
    F: FnOnce() -> Fut,
    Fut: Future<Output = ()>,
{
    init_test_logging();
    test_lab().run(f);
}

/// Run async test with Cx access.
pub fn run_test_with_cx<F, Fut>(f: F)
where
    F: FnOnce(&Cx) -> Fut,
    Fut: Future<Output = ()>,
{
    init_test_logging();
    test_lab().run_with_cx(|cx| f(&cx));
}
